/* Weather widget styling */
.Weather {
margin: 2.7rem;
padding: 1rem;
// border-left-width: 7px;
// border-left-style: solid;
// margin-left: 24px;
// margin-right: 24px;
border-right-width: 7px;
 border-right-style: solid;
 color: #90ffa4; /* Green text for weather information */
 text-align: center; /* Center-align the content */
 display: block; /* Ensures block-level behavior */
}
.Weather .summary {
  background-color: rgba(22, 160, 243, 0.3); /* Light blue background */
}
.Weather .temperature {
  color: #5cff4b; /* Bright green for temperature */
  line-height: 3em; /* Spacing between lines */
  padding: 1.3rem .3em; /* Padding for internal spacing */
  text-shadow: 2px -2px 1px #000000, 4px -3px 6px #f0fff0; /* Shadow for depth */
  background-color: rgba(4, 166, 113, 0.4); /* Light green background */
  box-shadow: 3px 3px 1px #90ffa4, 9px 8px 1px #0Aff04; /* Dual green shadow effect */
}
.Weather .details {
  font-size: 1.1rem; /* Medium font size for details */
  color: #90ffa4; /* Matching text color with header */
  background-color: rgba(1, 160, 123, 0.3); /* Muted green background */
}
.Weather .summary i,
.Weather .summary .high,
.Weather .summary .low,
.Weather .details dl {
  display: flex; /* Align items in a row */
  flex-flow: column; /* Reverse column order */
  margin: 18px; /* Adjust spacing */
}
.Weather {
  transform: translateX(42px); /* Shifts the widget horizontally */
}
/* Icon customization for weather conditions */
path[d="M18 10h-1.26A8 8 0 1 0 9 20h9a5 5 0 0 0 0-10z"] {
  stroke: #b3b3b3; /* Light gray outline */
}
svg circle[cx="12"][cy="12"][r="5"], 
svg circle[cx="12"][cy="12"][r="5"] ~ line {
  stroke: yellow; /* Yellow for sun representation */
}
svg > line[x1="16"][y1="13"][x2="16"][y2="21"], 
svg > line[x1="16"][y1="13"][x2="16"][y2="21"] ~ line {
  stroke: skyblue; /* Light blue for raindrops */
}
svg > line[x1="16"][y1="13"][x2="16"][y2="21"] ~ line + path {
  stroke: grey; /* Gray for background rain path */
}



